import React, { useState, useEffect } from 'react';
import './App.css';
import HomePage from './component/HomePage';
import AddRoomPage from './component/AddRoomPage';
import Header from './component/Header';
import AddDecoPage from './component/AddDecoPage';
import EditRoom from './component/EditRoom';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import MyRooms from './component/MyRooms';


function App() {
  const [rooms, setRooms] = useState([])

  let addRoom = (room) => {
    setRooms([...rooms,room])
  }

  let addNewDeco = (name, newDeco) => {
    let r = rooms.map((i) => {
      if (i.name == name) {
        return ({ name: i.name, roomType: i.roomType, color: i.color, items: [...i.items,newDeco] })
      }
      else{
        return({ name: i.name, roomType: i.roomType, color: i.color, items: i.items })}
    })
    setRooms(r)
  }
  let turnOnOrOff = (name, index, status) => {
    let r = rooms.map((i) => {
      if (i.name == name) {

        return({ name: i.name, roomType: i.roomType, color: i.color, items: [...i.items,newDeco] })
      }
      else{
        return({ name: i.name, roomType: i.roomType, color: i.color, items: i.items })}
    })
    setRooms(r)
  }

  return (
    <div className="App">
      <Header />
      <Router>
        <Routes>
          <Route path={'/'} element={<HomePage />} />
          <Route path={'/addroom'} element={<AddRoomPage addRoom={addRoom} />} />
          <Route path={'/myrooms'} element={<MyRooms rooms={rooms} />} />
         {rooms.map((item) => {return (<Route path={"room/" + item.name}element={ <EditRoom room={item} turnOnOrOff={turnOnOrOff}/>}/>);})}
          {rooms.map((item) => {
                console.log(item)
            return (<Route path={"room/"+item.name + "/additems"} element={<AddDecoPage name={item.name} addNewDeco={addNewDeco} />} />)})};
        </Routes>
      </Router>
    </div>)
}
export default App;
